python3 << 'EOF'
import json

# Read and validate JSON
with open('/workspace/implementors.json', 'r') as f:
    data = json.load(f)

print(f"Total implementors found: {len(data)}")
print(f"\nBreakdown by repository:")

repos = {}
for item in data:
    repo = item['repo']
    if repo not in repos:
        repos[repo] = 0
    repos[repo] += 1

for repo, count in sorted(repos.items()):
    print(f"  {repo}: {count}")

print(f"\nBreakdown by top API groups:")
api_groups = {}
for item in data:
    if item['repo'] == 'kubernetes/api':
        # Extract API group from file path
        parts = item['file'].split('/')
        if len(parts) >= 2:
            group = parts[0]
            if group not in api_groups:
                api_groups[group] = 0
            api_groups[group] += 1

print("API Groups in kubernetes/api:")
for group, count in sorted(api_groups.items()):
    print(f"  {group}: {count}")

# Verify no duplicates
names = [(item['repo'], item['file'], item['struct_name']) for item in data]
unique_names = set(names)
if len(names) == len(unique_names):
    print("\n✓ No duplicate entries found")
else:
    print(f"\n✗ Found {len(names) - len(unique_names)} duplicate entries")

EOF

